import React, { Component } from "react";
import ReactDOM from "react-dom";

class Creator extends Component {

    constructor(props) {
        super(props)
        this.state = {
            innerHTML: (
                <>
                    <h1>Вас приветствует генератор слайдеров! <br /><br /> Для начала нажмите кнопку СТАРТ</h1>
                </>
            )
        }
    }

    render() {
        return (
            <div className="container">
                { this.state.innerHTML }
            </div>
        )
    }
}

ReactDOM.render(
    <Creator />,
    document.querySelector('#App')
)
